import { codeToHtml } from "shiki"
import { CodeHeader } from "./CodeHeader"

interface CodeBlockProps {
  code: string
  language?: string
  filename?: string
  filepath?: string
  highlightLines?: number[]
  showLineNumbers?: boolean
  startingLineNumber?: number
}

function decorateShikiHtml(
  html: string,
  highlightLines: number[],
  showLineNumbers: boolean,
  startingLineNumber: number
): string {
  let lineIndex = 0

  return html.replace(/<span class="line">/g, () => {
    const lineNumber = startingLineNumber + lineIndex
    lineIndex += 1

    const classes = ["line"]

    if (showLineNumbers) {
      classes.push("code-line-numbered")
    }

    if (highlightLines.includes(lineNumber)) {
      classes.push("highlight-line")
    }

    return `<span class="${classes.join(" ")}" data-line="${lineNumber}">`
  })
}

function patchPreTag(html: string): string {
  return html.replace(
    /<pre class="shiki/g,
    '<pre class="shiki codeblock-pre scrollbar-hidden'
  )
}

export async function CodeBlock({
  code,
  language = "ts",
  filename,
  filepath,
  highlightLines = [],
  showLineNumbers = true,
  startingLineNumber = 1,
}: CodeBlockProps) {
  if (!code || !code.trim()) {
    return (
      <div className="overflow-hidden rounded-xl border border-white/10 bg-[#12141a]">
        <CodeHeader
          filename={filename}
          filepath={filepath}
          language={language}
          code=""
        />
        <div className="px-4 py-4 text-sm text-white/45">empty code block</div>
      </div>
    )
  }

  let html = await codeToHtml(code, {
    lang: language,
    theme: "vitesse-dark",
  })

  html = patchPreTag(html)
  html = decorateShikiHtml(
    html,
    highlightLines,
    showLineNumbers,
    startingLineNumber
  )

  return (
    <div className="overflow-hidden rounded-xl border border-white/10 bg-[#12141a] shadow-sm">
      <CodeHeader
        filename={filename}
        filepath={filepath}
        language={language}
        code={code}
      />

      <div
        className="docs-codeblock text-sm"
        dangerouslySetInnerHTML={{ __html: html }}
      />
    </div>
  )
}

export default CodeBlock