"use client"

import { useState } from "react"

import { extractLines, readCodeFile } from "@/lib/docs/code.utils"
import { CodeBlock } from "./CodeBlock"

interface CodeExampleProps {
  filepath: string
  language?: string
  filename?: string
  snippetRange?: string
  snippetHighlight?: string
  fullCodeHighlight?: string
  snippetTitle?: string
  fullFileTitle?: string
}

function parseRange(range?: string): { start?: number; end?: number } {
  if (!range) return {}

  const match = range.trim().match(/^(\d+)\s*-\s*(\d+)$/)
  if (!match) return {}

  return {
    start: Number(match[1]),
    end: Number(match[2]),
  }
}

function parseHighlightLines(input?: string): number[] {
  if (!input?.trim()) return []

  const values = new Set<number>()

  for (const part of input.split(",")) {
    const token = part.trim()
    if (!token) continue

    const rangeMatch = token.match(/^(\d+)\s*-\s*(\d+)$/)

    if (rangeMatch) {
      const start = Number(rangeMatch[1])
      const end = Number(rangeMatch[2])

      for (let i = start; i <= end; i += 1) {
        values.add(i)
      }

      continue
    }

    const single = Number(token)
    if (!Number.isNaN(single)) {
      values.add(single)
    }
  }

  return [...values].sort((a, b) => a - b)
}

function toAbsoluteSnippetHighlight(
  lines: number[],
  snippetStart?: number
): number[] {
  if (!snippetStart) return lines
  return lines.map((line) => snippetStart + line - 1)
}

export default function CodeExample({
  filepath,
  language = "ts",
  filename,
  snippetRange,
  snippetHighlight,
  fullCodeHighlight,
  snippetTitle = "Focused extract",
  fullFileTitle = "Full file",
}: CodeExampleProps) {
  const [expanded, setExpanded] = useState(false)

  const source = readCodeFile(filepath)
  const { start, end } = parseRange(snippetRange)
  const snippet = extractLines(source, start, end)

  const snippetHighlightLines = toAbsoluteSnippetHighlight(
    parseHighlightLines(snippetHighlight),
    start
  )

  const fullCodeHighlightLines = parseHighlightLines(fullCodeHighlight)

  return (
    <div className="my-8 overflow-hidden rounded-xl border border-white/10 bg-[#12141a] shadow-sm">
      <div className="sticky top-2 z-20 flex items-center justify-between gap-4 border-b border-white/10 bg-[#12141a]/95 px-4 py-3 text-sm backdrop-blur supports-[backdrop-filter]:bg-[#12141a]/80">
        <div className="min-w-0">
          <div className="font-medium text-white">
            {expanded ? fullFileTitle : snippetTitle}
          </div>
          <div className="truncate text-xs text-white/45">
            {filename ?? filepath}
          </div>
        </div>

        <button
          type="button"
          onClick={() => setExpanded((value) => !value)}
          className="shrink-0 rounded-md border border-white/10 bg-white/[0.04] px-3 py-1 text-xs text-white/70 transition-colors hover:bg-white/[0.07] hover:text-white"
        >
          {expanded ? "Revenir à l’extrait" : "Voir le fichier complet"}
        </button>
      </div>

      <div>
        {expanded ? (
          <CodeBlock
            code={source}
            language={language}
            filename={filename}
            filepath={filepath}
            highlightLines={fullCodeHighlightLines}
            showLineNumbers={true}
            startingLineNumber={1}
          />
        ) : (
          <CodeBlock
            code={snippet}
            language={language}
            filename={filename}
            filepath={filepath}
            highlightLines={snippetHighlightLines}
            showLineNumbers={true}
            startingLineNumber={start ?? 1}
          />
        )}
      </div>
    </div>
  )
}